class Solution:
    def simplifyPath(self, path):
        out = []
        for seg in path.split('/'):
            if seg == '' or seg == '.':
                continue
            if seg == '..':
                if out:
                    out.pop()
            else:
                out.append(seg)
        return '/' + '/'.join(out)

