var simplifyPath = function(path) {
    const stack = [];
    for (const seg of path.split('/')) {
        if (seg === '' || seg === '.') continue;
        if (seg === '..') {
            if (stack.length) stack.pop();
        } else {
            stack.push(seg);
        }
    }
    return '/' + stack.join('/');
};
